(function(){window.SmokeTest=window.SmokeTest||{},window.SmokeTest.Helpers=window.SmokeTest.Helpers||{},window.SmokeTest.Config=window.SmokeTest.Config||{timeouts:{route:5e3,interact:2500,battle:5e3},perfBudget:{turnMs:6,drawMs:12}};const t={makeBudget(o){const e=Date.now()+Math.max(0,o|0);return{exceeded:()=>Date.now()>e,remain:()=>Math.max(0,e-Date.now())}}};window.SmokeTest.Helpers.Budget=t})();
